#!/usr/bin/env bash
# Submit sketches + HCEM Cloud Build for 5 small transformer models.
# Models: smollm2-360m, gemma3-1b-it, deepseek-r1-1.5b, gemma3-4b-it, phi-3.5-mini
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI="$SCRIPT_DIR/distributed-inference"
YAML="$SCRIPT_DIR/cloudbuild-small-model-sketches-and-hcem.yaml"

TMPDIR="$(mktemp -d)"
trap 'rm -rf "$TMPDIR"' EXIT

mkdir -p "$TMPDIR/open-source/gnosis/distributed-inference"

cp "$YAML" "$TMPDIR/"
cp "$DI/generate-sketches.py"    "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/make-columnar-embed.py"  "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/sketch_knot_format.py"   "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/encode-real-model.py"    "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/upload-to-r2.py"         "$TMPDIR/open-source/gnosis/distributed-inference/"

echo "[submit] tmpdir contents:"
find "$TMPDIR" -type f | sort

echo "[submit] submitting build (5 transformers: smollm2-360m gemma3-1b-it deepseek-r1-1.5b gemma3-4b-it phi-3.5-mini)"
gcloud builds submit "$TMPDIR" \
  --config="$TMPDIR/cloudbuild-small-model-sketches-and-hcem.yaml" \
  --project=neutral-418500 \
  --async
